  legacyDtSdk.dtSdk.getAppId = wrapper.getAppId;
  legacyDtSdk.dtSdk.getAppName = wrapper.getAppName;
  legacyDtSdk.dtSdk.getAppVersion = wrapper.getAppVersion;
